def p(g):
    h, w = len(g), len(g[0])
    # find sprite cells (non-zero, non-2)
    sc = []
    col = 0
    for r in range(h):
        for c in range(w):
            v = g[r][c]
            if v not in (0, 2):
                if not sc:
                    col = v
                sc.append((r, c))
    if not sc:
        return []  # fallback
    # sprite bounding box
    min_r = min(r for r, c in sc)
    min_c = min(c for r, c in sc)
    # 3x3 pattern
    pat = [[0]*3 for _ in range(3)]
    for r, c in sc:
        pat[r - min_r][c - min_c] = col
    # red box bounding box
    red = [(r, c) for r in range(h) for c in range(w) if g[r][c] == 2]
    min_br = min(r for r, c in red)
    max_br = max(r for r, c in red)
    min_bc = min(c for r, c in red)
    max_bc = max(c for r, c in red)
    outsize = max_br - min_br + 1
    m = (outsize - 2) // 3
    # output grid
    out = [[0]*outsize for _ in range(outsize)]
    # draw magnified sprite
    for i in range(3):
        for j in range(3):
            if pat[i][j]:
                for di in range(m):
                    for dj in range(m):
                        out[1 + i*m + di][1 + j*m + dj] = pat[i][j]
    # draw red border
    for i in range(outsize):
        out[0][i] = out[outsize-1][i] = out[i][0] = out[i][outsize-1] = 2
    return out

